declare @xstt varchar(32), @use_ma_sp bit, @use_ma_vv bit, @use_ma_bp bit, @use_so_lsx bit, @use_ma_hd bit, @use_ma_ku bit, @use_ma_phi bit, @gd_yn bit, @ct_yn bit, @xl_yn bit, @hide varchar(1024), @trung_so int, @cb_yn bit
select @gd_yn = case when exists(select 1 from dmmagd where ma_ct = @ma_ct) then 1 else 0 end, @xl_yn = case when exists(select 1 from dmxlct where ma_ct = @ma_ct) then 1 else 0 end
if @gd_yn = 1 select @ct_yn = 0
  else select @ct_yn = case when exists(select 1 from dmloaict where ma_ct = @ma_ct) then 1 else 0 end
select @hide = ',' + replace(rtrim(ltrim(hide)), ' ', '') + ',' from @@sysDatabaseName..voucherinfo where ma_ct = @ma_ct
select @use_ma_vv = 1, @use_ma_sp = case when charindex(',ma_sp,', @hide ) = 0 then 1 else 0 end, @use_ma_bp = case when charindex(',ma_bp,', @hide ) = 0 then 1 else 0 end, @use_so_lsx = case when charindex(',so_lsx,', @hide ) = 0 then 1 else 0 end, @use_ma_hd = case when charindex(',ma_hd,', @hide ) = 0 then 1 else 0 end, @use_ma_ku = case when charindex(',ma_ku,', @hide ) = 0 then 1 else 0 end, @use_ma_phi = case when charindex(',ma_phi,', @hide ) = 0 then 1 else 0 end
select @xstt = xstt, @trung_so = abs(m_trung_so), @cb_yn = case when m_trung_so < 0 then 1 else 0 end from vdmct where ma_ct = @ma_ct
select @use_ma_sp as use_ma_sp, @use_ma_vv as use_ma_vv, @use_ma_bp as use_ma_bp, @use_so_lsx as use_so_lsx, @use_ma_hd as use_ma_hd, @use_ma_ku as use_ma_ku, @use_ma_phi as use_ma_phi, @gd_yn as gd_yn, @ct_yn as ct_yn, @xl_yn as xl_yn, @trung_so as trung_so, @xstt as xstt, @cb_yn as cb_yn&Config.InitExternalFields.Select;
return







declare @$u1 bit, @$u2 bit, @$u3 bit, @$p1 tinyint, @$p2 tinyint, @$p3 tinyint, @hide varchar(1024), @group varchar(1024)
select @$p1 = post_td1, @$p2 = post_td2, @$p3 = post_td3 from dmct where ma_ct = @ma_ct
select @hide = ',' + replace(rtrim(ltrim(hide)), ' ', '') + ',' from @@sysDatabaseName..voucherinfo where ma_ct = @ma_ct
select @$u1 = case when charindex(',ma_td1,', @hide ) = 0 then 1 else 0 end, @$u2 = case when charindex(',ma_td2,', @hide ) = 0 then 1 else 0 end, @$u3 = case when charindex(',ma_td3,', @hide ) = 0 then 1 else 0 end
select @hide = '', @group = 'ma_vv' + case when @post_sp = 1 then ', ma_sp' else '' end + case when @post_bp = 1 then ', ma_bp' else '' end + case when @post_lsx = 1 then ', so_lsx' else '' end + case when @post_hd = 1 then ', ma_hd' else '' end + case when @post_ku = 1 then ', ma_ku' else '' end + case when @post_phi = 1 then ', ma_phi' else '' end + case when @$p1 = 1 then ', ma_td1' else '' end + case when @$p2 = 1 then ', ma_td2' else '' end + case when @$p3 = 1 then ', ma_td3' else '' end

if @$use_ma_sp = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_sp'
if @$use_ma_bp = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_bp'
if @$use_so_lsx = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'so_lsx'
if @$use_ma_hd = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_hd'
if @$use_ma_ku = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_ku'
if @$use_ma_phi = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_phi'
if @$u1 = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_td1'
if @$u2 = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_td2'
if @$u3 = 0 select @hide = @hide + case when @hide = '' then '' else ', ' end + 'ma_td3'

select @group = @group + case when @group = '' then '' else ', ' end + rtrim(c.field)
  from @@sysDatabaseName..freecolumns a join @@sysDatabaseName..freefunctions b on a.controller = b.controller and b.ma_ct = @ma_ct left join @@sysDatabaseName..sysfreecolumns c on a.id = c.id
  where a.post_yn = 1 and a.status = 1 and a.id not in ('C1', 'C2', 'C3')
&Config.Updating;
update @@sysDatabaseName..voucherinfo set hide = @hide, groupby = @group where ma_ct = @ma_ct







update @@table set m_trung_so = case when @$cb_yn = 1 then -@$trung_so else @$trung_so end, datetime2 = getdate(), user_id2 = @@userID where ma_ct = @ma_ct

        &Config.Updated;






      &OutlineEntry;

function initForm(f) {
  f._tabContainer.add_activeTabChanged(onTabChanged);
  f.add_onResponseComplete(on$Form$ResponseComplete);
  f._tabContainer._loaded = true;
  if (f._controlFocus) f._controlFocus = f.getItem('ten_ct');
	try {f.getItem('ten_ct').focus();} catch (ex) {}
  var c = f.getItem('m_ma_gd'), t = f.getItem('m_loai_ct'), a = f.getItem('m_status');
  if (!f.getItemValue('voucher_yn')) {try {
    c.disabled = t.disabled = a.disabled = true;
    f._setReadOnly(c, true);
    f._setReadOnly(t, true);
    f._setReadOnly(a, true);
    f._tabContainer.get_tabs()[2]._hide();
  } catch (ex) {}}
  else {
    setReferenceObject(f, 'gd_yn', c);
    setReferenceObject(f, 'ct_yn', t);
    setReferenceObject(f, 'xl_yn', a);
    &Config.Tab;
  }
  onVoucherCheckSelectedIndexChanged(f.getItem('trung_so'));
  var o = f.getItem('post_lsx');
  if (o.field.Hidden) $common.setVisible(o.parentNode.parentNode.parentNode, false);
}
/* <flatten type="Javascript"> */
function closeForm(f) {
  try {f.remove_onResponseComplete(on$Form$ResponseComplete);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged);} catch (ex) {}
}
function onTabChanged(sender, e) {sender.parentForm.focusWhenTabChanged(['ma_ct_me', 'tieu_de_ct', 'use_ma_bp']);}
function onVoucherCheckSelectedIndexChanged(o) {o.parentForm.getItem('cb_yn').disabled = (o.parentForm.getItemValue('trung_so') == 0);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_ct', 'm_ma_gd']);}
function setReferenceObject(f, c, o) {
  f.setReferenceKeyFilter(o.field.Name);
  if (!f.getItemValue(c)) {
    o.disabled = true;
    f._setReadOnly(o, true);
  }
}
function on$Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Transaction':
      f.setItemControlBehavior('m_loai_ct', result[0].Value, result[1].Value, true);
      break;
	  default:
      break;
	}
}
/* </flatten> */







select rtrim(a.loai_ct) as loai_ct, b.ten_loai%l as ten_loai from dmmagd a left join dmloaict b on a.loai_ct = b.loai_ct and a.ma_ct = b.ma_ct
  where a.ma_ct = @ma_ct and a.ma_gd = @m_ma_gd
return





